/* Test driver */
public class Main {
    public static void main(String[] args) {
        URLShortener s = new URLShortener("https://s.ly", new EncodingStrategy.RandomEncoding());
        String shortUrl = s.shorten("https://example.com/foo");
        String resolved = s.resolve(shortUrl);
        if ("https://example.com/foo".equals(resolved)) System.out.println("OK_ROUNDTRIP");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        URLShortener s = new URLShortener("https://s.ly", new EncodingStrategy.RandomEncoding());
        String a = s.shorten("https://example.com/x");
        String b = s.shorten("https://example.com/x");
        if (a.equals(b) && s.getTotalMappings() == 1) System.out.println("OK_DEDUP");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        URLShortener s = new URLShortener("https://s.ly", new EncodingStrategy.RandomEncoding());
        try {
            s.resolve("https://s.ly/nope123");
            System.out.println("WRONG_NO_EX");
        } catch (IllegalArgumentException e) {
            System.out.println("OK_NOTFOUND");
        }
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        URLShortener s = new URLShortener("https://s.ly", new EncodingStrategy.RandomEncoding());
        s.shorten("https://a.com");
        s.shorten("https://b.com");
        s.shorten("https://c.com");
